/**
 * 9201051 - multi-role custom NPC (John Barricade sprite). Generated by gen_shops.py.
 *   map 10000     -> Welcome NPC (#1)
 *   map 600020000 -> John Barricade original (New Leaf City) - preserved
 *   any other map -> Server Hub (#4): the placed Henesys NPC
 * The base scripts/npc/9201051.js is NOT changed (this is an en-US override).
 */

var COMMANDS = [
    ["@taxi", "Free teleport to every main town"],
    ["@reborn", "Rebirth at max level (back to Beginner, +1 reborn)"],
    ["@jobup", "Job advancement, 1st through 4th"],
    ["@salon", "Change hair, face, skin tone and colors"],
    ["@teleport", "Warp to bosses, level maps, towns and events"],
    ["@learnskill", "Learn Double Jump (-) and Teleport (+)"],
    ["@maxskills", "Max every skill for your current job (no books)"],
    ["@guild", "Create a guild solo (no party), edit emblem, manage it"],
    ["@newbiegift", "One-time starter gift"],
    ["@checkin", "Daily check-in reward"],
    ["@onlinereward", "Reward for time spent online"],
    ["@mapdrops", "See what the current map drops"],
    ["@deleteitems", "Clean out an inventory tab"]
];

var GM_COMMANDS = [
    ["@npcinfo", "Toggle the GM NPC id+script chat feedback (on/off)"]
];

var CATS = [
    ["Weapons & Class Gear", [["Warrior Gear I", 7000100, 300], ["Warrior Gear II", 7000101, 300], ["Warrior Gear III", 7000102, 231], ["Magician Gear I", 7000103, 300], ["Magician Gear II", 7000104, 109], ["Bowman Gear I", 7000105, 300], ["Bowman Gear II", 7000106, 119], ["Thief Gear I", 7000107, 300], ["Thief Gear II", 7000108, 211], ["Pirate Gear", 7000109, 142]]],
    ["Armor & Accessories", [["Hats I", 7000200, 300], ["Hats II", 7000201, 300], ["Hats III", 7000202, 36], ["Tops I", 7000203, 300], ["Tops II", 7000204, 263], ["Bottoms", 7000205, 209], ["Shoes", 7000206, 198], ["Gloves", 7000207, 62], ["Shields", 7000208, 16], ["Capes", 7000209, 177], ["Accessories I", 7000210, 300], ["Accessories II", 7000211, 300], ["Accessories III", 7000212, 9]]],
    ["Consumables", [["Potions", 7000300, 55], ["Scrolls I", 7000301, 300], ["Scrolls II", 7000302, 300], ["Scrolls III", 7000303, 154], ["Food & Buffs I", 7000304, 300], ["Food & Buffs II", 7000305, 222], ["Ammo", 7000306, 29], ["Misc Use I", 7000307, 300], ["Misc Use II", 7000308, 300], ["Misc Use III", 7000309, 300], ["Misc Use IV", 7000310, 30]]],
    ["Setup", [["Setup Furniture", 7000400, 294]]],
    ["Etc", [["Crafting", 7000500, 117], ["Books & Guides", 7000501, 91], ["Minerals & Gems", 7000502, 38], ["Minigame", 7000503, 30], ["Misc Etc", 7000504, 150]]],
    ["Boss Drops", [["Boss Equipment", 7000600, 89]]],
    ["Anniversary & Maple", [["Anniversary & Maple Gear", 7000700, 154]]]
];

// stage 0 = main menu, 1 = shop category (shops + Back), 2 = command info (text + Back)
var stage = 0;
var cat = -1;
var cmd = -1;
var cmdGm = false;

// Flat, ordered list of the main-menu's selectable lines so click indices always
// match what hubMain() renders (commands, then categories, then GM section).
function hubItems() {
    var items = [];
    for (var c = 0; c < COMMANDS.length; c++) { items.push(["cmd", c]); }
    for (var s = 0; s < CATS.length; s++) { items.push(["cat", s]); }
    if (cm.getPlayer().isGM()) {
        for (var g = 0; g < GM_COMMANDS.length; g++) { items.push(["gmcmd", g]); }
        items.push(["gmshop", 0]);
    }
    return items;
}

function hubMain() {
    var t = "#e#rServer Hub#k#n\r\n";
    t += "Pick a #bcommand#k for info or a #bshop#k to browse.\r\n";
    var i = 0;
    t += "\r\n#r#eCommands#k#n\r\n";
    for (var c = 0; c < COMMANDS.length; c++) {
        t += "#L" + i + "##b" + COMMANDS[c][0] + "#k#l\r\n";
        i++;
    }
    t += "\r\n#r#eShops#k#n\r\n";
    for (var s = 0; s < CATS.length; s++) {
        t += "#L" + i + "##b" + CATS[s][0] + "#k#l\r\n";
        i++;
    }
    if (cm.getPlayer().isGM()) {
        t += "\r\n#r#eGM#k#n\r\n";
        for (var g = 0; g < GM_COMMANDS.length; g++) {
            t += "#L" + i + "##b" + GM_COMMANDS[g][0] + "#k#l\r\n";
            i++;
        }
        t += "#L" + i + "##bGM Shop#k#l\r\n";
        i++;
    }
    cm.sendSimple(t);
}

function hubOnMain(selection) {
    var items = hubItems();
    if (selection < 0 || selection >= items.length) { cm.dispose(); return; }
    var it = items[selection];
    if (it[0] == "cmd") { cmd = it[1]; cmdGm = false; stage = 2; hubCmdInfo(); }
    else if (it[0] == "cat") { cat = it[1]; stage = 1; hubCat(); }
    else if (it[0] == "gmcmd") { cmd = it[1]; cmdGm = true; stage = 2; hubCmdInfo(); }
    else if (it[0] == "gmshop") { cm.openShopNPC(1337); cm.dispose(); }
    else { cm.dispose(); }
}

function hubCmdInfo() {
    var list = cmdGm ? GM_COMMANDS : COMMANDS;
    var t = "#e#r" + list[cmd][0] + "#k#n\r\n\r\n" + list[cmd][1]
          + "\r\n\r\nType #b" + list[cmd][0] + "#k in the chat to use it.\r\n\r\n";
    t += "#L0##rBack to menu#k#l";
    cm.sendSimple(t);
}

function hubCat() {
    var shops = CATS[cat][1];
    var t = "#e#r" + CATS[cat][0] + "#k#n\r\n\r\n";
    // Keep the count INSIDE the #L..#l link (no trailing text after #l) so nothing overlaps.
    for (var i = 0; i < shops.length; i++) {
        t += "#L" + i + "##b" + shops[i][0] + "#k (" + shops[i][2] + " items)#l\r\n";
    }
    t += "\r\n#L" + shops.length + "##rBack to menu#k#l";
    cm.sendSimple(t);
}

function hubOnCat(selection) {
    var shops = CATS[cat][1];
    if (selection >= 0 && selection < shops.length) {
        cm.openShopNPC(shops[selection][1]);
        cm.dispose();
    } else {                 // Back to menu
        stage = 0;
        hubMain();
    }
}

// Both command-info and (implicitly) any stray click return to the main menu.
function hubBackToMain() {
    stage = 0;
    hubMain();
}

var WELCOME_MAP = 10000;       // Maple Road / Mushroom Town -> Welcome NPC (#1)
var JOHN_MAP    = 600020000;   // New Leaf City -> John Barricade original

function start() {
    var m = cm.getMapId();
    if (m == WELCOME_MAP) {
        cm.sendOk("Welcome to #bMaple World#k! You're now playing on #bDevMS V83#k.\r\n\r\nWe're glad to have you here, #h #. Enjoy your adventure!");
        cm.dispose();
        return;
    }
    if (m == JOHN_MAP) {
        cm.sendOk("The patrol in #bNew Leaf City#k is always ready.\r\n\r\nNo creatures are able to break through to the city while we stand watch.");
        cm.dispose();
        return;
    }
    stage = 0;
    hubMain();   // Server Hub (#4): the placed Henesys NPC lands here
}

function action(mode, type, selection) {
    var m = cm.getMapId();
    if (m == WELCOME_MAP || m == JOHN_MAP) { cm.dispose(); return; }
    if (mode != 1) { cm.dispose(); return; }
    if (stage == 1) { hubOnCat(selection); }
    else if (stage == 2) { hubBackToMain(); }
    else { hubOnMain(selection); }
}
